class Solution {
public:
    string decodeDNA(int n, const string &s) {
        string result = "";
        for (int i = 0; i < n; i += 2) {
            if (s[i] == '0' && s[i+1] == '0') {
                result += 'A';
            }
            else if (s[i] == '0' && s[i+1] == '1') {
                result += 'T';
            }
            else if (s[i] == '1' && s[i+1] == '0') {
                result += 'C';
            }
            else {
                result += 'G';
            }
        }
        return result;
    }
};

code.Python3:
class Solution:
    def decodeDNA(self, n, s):
        result = []
        for i in range(0, n, 2):
            if s[i] == '0' and s[i+1] == '0':
                result.append('A')
            elif s[i] == '0' and s[i+1] == '1':
                result.append('T')
            elif s[i] == '1' and s[i+1] == '0':
                result.append('C')
            else:
                result.append('G')
        return "".join(result)

