void decodeDNA(int n, char s[], char result[]) {
    int k = 0;
    for (int i = 0; i < n; i += 2) {
        if (s[i] == '0' && s[i+1] == '0') {
            result[k++] = 'A';
        } else if (s[i] == '0' && s[i+1] == '1') {
            result[k++] = 'T';
        } else if (s[i] == '1' && s[i+1] == '0') {
            result[k++] = 'C';
        } else {
            result[k++] = 'G';
        }
    }
    result[k] = '\0'; // Null terminate the string
}

code.Java:
class Solution {
    public String decodeDNA(int n, String s) {
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < n; i += 2) {
            if (s.charAt(i) == '0' && s.charAt(i + 1) == '0') {
                result.append('A');
            } else if (s.charAt(i) == '0' && s.charAt(i + 1) == '1') {
                result.append('T');
            } else if (s.charAt(i) == '1' && s.charAt(i + 1) == '0') {
                result.append('C');
            } else {
                result.append('G');
            }
        }
        return result.toString();
    }
}

